import React from "react";
import { useCurrentFrame } from "remotion";

// Deterministic star positions — stable across all frames, only opacity twinkles
const STARS = Array.from({ length: 80 }, (_, i) => ({
  x: ((i * 7919 + 13) % 1000) / 10,     // 0–100 range
  y: ((i * 6271 + 37) % 650) / 10,      // 0–65 (upper sky portion only)
  size: 1 + (i % 3) * 0.5,
  twinkleSpeed: 0.025 + (i % 9) * 0.007,
  twinkleOffset: (i * 1.47) % (Math.PI * 2),
}));

const GRID_CELL = 80; // px — perspective grid cell size

export const AnimatedBackground: React.FC = () => {
  const frame = useCurrentFrame();

  // Grid scrolls toward the viewer — loops every GRID_CELL frames
  const gridScrollY = (frame * 1.0) % GRID_CELL;

  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        background: "#05040e",
        overflow: "hidden",
      }}
    >
      {/* ── Starfield ───────────────────────────────────────────── */}
      <svg
        style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }}
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
      >
        {STARS.map((star, i) => {
          const opacity =
            0.35 + Math.sin(frame * star.twinkleSpeed + star.twinkleOffset) * 0.30;
          return (
            <circle
              key={i}
              cx={star.x}
              cy={star.y}
              r={star.size * 0.12}
              fill="white"
              opacity={Math.max(0.05, opacity)}
            />
          );
        })}
      </svg>

      {/* ── Perspective grid floor — Tron / Futurama style ─────── */}
      <div
        style={{
          position: "absolute",
          bottom: 0,
          left: "-60%",
          right: "-60%",
          height: "52%",
          backgroundImage: `
            linear-gradient(rgba(0,242,254,0.20) 1px, transparent 1px),
            linear-gradient(90deg, rgba(0,242,254,0.20) 1px, transparent 1px)
          `,
          backgroundSize: `${GRID_CELL}px ${GRID_CELL}px`,
          backgroundPosition: `0 ${gridScrollY}px`,
          transform: "perspective(280px) rotateX(68deg)",
          transformOrigin: "50% 0%",
          maskImage:
            "linear-gradient(to bottom, transparent 0%, black 25%, black 85%, transparent 100%)",
          WebkitMaskImage:
            "linear-gradient(to bottom, transparent 0%, black 25%, black 85%, transparent 100%)",
        }}
      />

      {/* ── Horizon neon line — cian fading to magenta ──────────── */}
      <div
        style={{
          position: "absolute",
          bottom: "47%",
          left: 0,
          right: 0,
          height: 3,
          background:
            "linear-gradient(90deg, transparent 0%, rgba(0,242,254,0.75) 25%, rgba(240,147,251,0.75) 75%, transparent 100%)",
          filter: "blur(2px)",
          boxShadow: "0 0 14px rgba(0,242,254,0.5), 0 0 32px rgba(0,242,254,0.2)",
        }}
      />

      {/* ── Neon blob — Leo side (cian, left) ───────────────────── */}
      <div
        style={{
          position: "absolute",
          left: "18%",
          top: "32%",
          width: 300,
          height: 300,
          borderRadius: "50%",
          background:
            "radial-gradient(circle, rgba(0,242,254,0.20) 0%, rgba(0,242,254,0.05) 55%, transparent 70%)",
          filter: "blur(28px)",
          transform: "translate(-50%, -50%)",
        }}
      />

      {/* ── Neon blob — Lola side (magenta, right) ──────────────── */}
      <div
        style={{
          position: "absolute",
          left: "82%",
          top: "32%",
          width: 280,
          height: 280,
          borderRadius: "50%",
          background:
            "radial-gradient(circle, rgba(240,147,251,0.20) 0%, rgba(240,147,251,0.05) 55%, transparent 70%)",
          filter: "blur(24px)",
          transform: "translate(-50%, -50%)",
        }}
      />

      {/* ── CRT scanlines ────────────────────────────────────────── */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage:
            "repeating-linear-gradient(0deg, transparent 0px, transparent 3px, rgba(0,0,0,0.10) 3px, rgba(0,0,0,0.10) 4px)",
          pointerEvents: "none",
        }}
      />

      {/* ── Vignette — darkens edges like a CRT monitor ─────────── */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "radial-gradient(ellipse at 50% 50%, transparent 48%, rgba(0,0,0,0.60) 100%)",
          pointerEvents: "none",
        }}
      />
    </div>
  );
};
